#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;

    vector<int> x(N);
    for (int i = 0; i < N; ++i) {
        cin >> x[i];
    }

    if (N <= 1) {
        cout << 0 << '\n';
        return 0;
    }

    sort(x.begin(), x.end());

    // dp[i] = min total length for first i nails (0-indexed)
    vector<int> dp(N, 0);
    dp[0] = 0;          // one nail needs no string
    dp[1] = x[1] - x[0]; // two nails must be connected

    for (int i = 2; i < N; ++i) {
        // Option 1: connect i to i-1 (pair them)
        // then subproblem for i-2
        int opt1 = dp[i - 2] + (x[i] - x[i - 1]);

        // Option 2: connect i to i-1 and also i-1 was already paired with i-2,
        // i.e. i-1,i-2 are paired, so i,i-1 is connected to i-2,i-1?
        // Actually the nail i-1 can be part of two strings to cover i-2 and i.
        // But we also need to consider that i-1 could be the "middle" nail
        // connecting i-2 and i.
        // Better approach: standard minimum cost to connect nails such that
        // each nail is incident to at least one string = minimum spanning tree
        // on a complete graph where weight = distance.
        // But N <= 100, coordinates on a line, so MST = sum of consecutive gaps
        // after sorting? No — MST on line connects all points with N-1 edges
        // covering all nails. However the problem says "each nail is connected
        // to at least one string", not that all nails must be in a single connected
        // component. So we can leave gaps. The minimum is to connect each nail
        // to its nearest neighbor, but that's not simply pairing consecutive.
        //
        // Let's re-read: "Хадаас бүр ядаж нэг уяанд холбогдсон байхаар"
        // Each nail is incident to at least one string.
        // Strings can connect any two nails. We want min sum of string lengths.
        //
        // This is exactly: find a set of edges such that every vertex has degree >= 1,
        // minimizing sum of edge weights. This is the minimum-weight edge cover problem.
        // On a general graph it's solvable via matching, but on a line (sorted coordinates)
        // it has a simple DP:
        // dp[i] = min cost to cover first i nails (0-indexed).
        // dp[0] = 0 (no nails)
        // dp[1] = INF? Actually with 1 nail, no edges needed, cost = 0.
        // But our indexing: dp[i] for i nails.
        // Let's redo:
        // dp[i] = min cost to cover nails 0..i (inclusive) where nail i is covered.
        // We can pair i with i-1, or we can skip covering i-1 specifically?
        //
        // Edge cover on a path graph. On a path, the minimum edge cover is:
        // DP[i] = min(DP[i-2] + w(i-1,i), DP[i-1] + w(i-1,i))? Not exactly.
        //
        // Let's just implement the general minimum weight edge cover via
        // reduction to maximum weight matching, but N <= 100 we can do DP
        // on sorted coordinates properly.
        //
        // Actually the problem is classic: given points on a line, connect them
        // with segments so each point touches at least one segment, minimize total
        // segment length. This is known as "minimum edge cover on a path graph"
        // and the DP is:
        // Let nails sorted: a[0..N-1]
        // dp[0] = 0
        // dp[1] = INF (impossible to cover 2 points with 1 edge? No, one edge covers both)
        // Actually dp[i] = min cost to cover first i points (0-indexed up to i).
        // For i=0: cost 0.
        // For i>=1:
        //   dp[i] = min over k from 0..i-1 of dp[k-1] + (a[i] - a[k])  where we cover k..i with one edge
        // But a single edge covers both endpoints, so if we put edge (k,i), it covers k and i.
        // Points k+1..i-1 might be left uncovered! So we need to ensure all points are covered.
        //
        // Simpler: minimum edge cover on a line graph:
        // Each edge covers its two endpoints. We want to select edges so every vertex is incident
        // to at least one selected edge.
        //
        // On a line where edges exist only between consecutive vertices (since non-consecutive
        // edge would be longer and wasteful), the optimal edge cover uses only consecutive edges.
        // Proof: any edge (i,j) with j>i+1 can be replaced by edges (i,i+1), (i+1,i+2), ..., (j-1,j)
        // which cover the same vertices and total length = a[j]-a[i] = same! So no benefit to skip.
        // So we only consider edges between consecutive nails.
        //
        // Now we have a path graph with N vertices and N-1 edges (between consecutive sorted coords).
        // We need minimum weight edge cover on a path.
        //
        // DP: let the edges be e_i between a[i] and a[i+1], weight w_i = a[i+1]-a[i]
        // We need to select a subset of edges such that every vertex is incident to >=1 selected edge.
        //
        // dp[i][0] = min cost to cover vertices 0..i such that vertex i is NOT incident to any selected edge
        //            (but then vertex i must be covered by... impossible if there's no edge to i.
        //             Actually if i is not incident, it's uncovered → invalid.)
        // dp[i][1] = min cost to cover vertices 0..i such that vertex i IS incident to a selected edge.
        //
        // For i=0 (single vertex 0):
        //   dp[0][0] = 0 (no edges, vertex 0 is not incident... but it's uncovered? Wait, a single nail
        //                 with no edges is already "connected" to a string? No, it needs to be connected
        //                 to at least one string. So a single nail needs no strings. So cost 0 is fine.)
        //   dp[0][1] = INF (impossible to have an incident edge because no edges)
        //
        // For i>=1, consider edge e_{i-1} between i-1 and i with weight w = a[i]-a[i-1]:
        //   Case: edge NOT selected
        //     dp[i][0] = dp[i-1][0]   -- but then vertex i is not incident, so invalid if i is last?
        //     Actually dp[i][0] means vertex i has no incident selected edge → invalid unless i is the
        //     last vertex and we don't need to cover it? No, every vertex must be incident.
        //     So dp[i][0] is only valid if we are not yet done... Actually for an intermediate vertex,
        //     it could be covered by the next edge. So dp[i][0] = dp[i-1][1] (since edge not selected,
        //     vertex i has no incident edge, but it could be covered later by edge i).
        //     But in DP we process left to right. If we decide edge e_{i-1} is NOT selected, then
        //     vertex i is not incident yet, but vertex i-1 must have been incident already (by dp[i-1][1]).
        //   So: dp[i][0] = dp[i-1][1]   (edge e_{i-1} not taken, i not incident yet)
        //
        //   Case: edge selected
        //     dp[i][1] = w + min(dp[i-1][0], dp[i-1][1])
        //     because if we take edge, vertex i-1 is covered (regardless of its previous state)
        //     and vertex i is covered.
        //
        // Base: dp[0][0] = 0, dp[0][1] = INF
        //
        // Answer for N nails: we need all vertices covered, so vertex N-1 must be incident.
        // Answer = dp[N-1][1]
        //
        // Let's verify with sample.
    }

    // Redo with proper DP
    if (N == 1) {
        cout << 0 << '\n';
        return 0;
    }

    sort(x.begin(), x.end());

    const int INF = 1e9;
    vector<int> dp0(N, INF), dp1(N, INF);
    dp0[0] = 0;  // vertex 0 not incident yet (will be covered by edge to 1)
    // dp1[0] stays INF

    for (int i = 1; i < N; ++i) {
        int w = x[i] - x[i - 1];
        // edge not selected
        dp0[i] = dp1[i - 1];
        // edge selected
        dp1[i] = w + min(dp0[i - 1], dp1[i - 1]);
    }

    cout << dp1[N - 1] << '\n';

    return 0;
}
